THE CLAIM:
{
 "title": "Year-1 reach is two countries, not 55% of the market",
 "narrative": "The model assumes the venture can serve 55% of its market in Year 1. But that reach must be built during the same 12 months, and the only outside analogues we found sit near 12%, not 45–65%. A realistic first-year footprint of Germany plus the Netherlands through one distributor is closer to 30–35% of the market than 55%.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "The 55% is a guess; every outside figure sits far lower",
   "refs": [
    "digest:serviceable-benchmark#c3",
    "digest:serviceable-benchmark#c13",
    "ledger:serviceableFactor"
   ]
  },
  {
   "step": "propagation",
   "text": "Reach must be built country by country during Year 1",
   "refs": [
    "digest:serviceable-benchmark#c12",
    "digest:serviceable-benchmark#c10",
    "ledger:geo.CH",
    "ledger:geo.other"
   ]
  },
  {
   "step": "model-impact",
   "text": "Year-1 share drops toward two countries, shrinking the revenue base",
   "refs": [
    "ledger:serviceableFactor",
    "ledger:geo.DE"
   ]
  }
 ],
 "falsifier": "Signed distribution deals and completed registrations covering at least 55% of the market within the first quarter after launch.",
 "category": "model-structure",
 "evidence": [
  {
   "title": "Serviceable Obtainable Market (SOM): How to Calculate It",
   "sourceType": "industry-report",
   "publisher": "Prospeo",
   "date": null,
   "excerpt": "SOM is the revenue you can realistically capture in 1-3 years. Not a fantasy percentage of SAM. Not a top-down slice of a Gartner number.",
   "url": "https://prospeo.io/s/serviceable-obtainable-market",
   "attached": true
  },
  {
   "title": "GTM Strategy Statistics & Benchmarks 2024",
   "sourceType": "industry-report",
   "publisher": "The Starr Conspiracy",
   "date": "2026-04-21",
   "excerpt": "Only 23% of B2B companies achieve their first-year revenue targets after product launch, according to a 2024 study by SiriusDecisions analyzing 847 tech companies.",
   "url": "https://www.thestarrconspiracy.com/insights/benchmarks/go-to-market-strategy-benchmarks",
   "attached": true
  },
  {
   "title": "Memphasys seals exclusive Thailand Felix deal, lifting FY2026 contracted revenue",
   "sourceType": "triangulation",
   "publisher": "TipRanks",
   "date": "2026-07-01",
   "excerpt": "Memphasys has signed an exclusive three-year distribution agreement... in Thailand... combined with its recently signed Vietnam deal — illustrating that pre-launch distribution reach is built one country at a time.",
   "url": "https://www.tipranks.com/news/company-announcements/memphasys-seals-exclusive-thailand-felix-deal-lifting-fy2026-contracted-revenue",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "geo.CH",
  "label": "Switzerland",
  "kind": "estimated",
  "value": 0.08,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "single-source",
  "dimension": "geography",
  "dimensionValue": "CH",
  "sensitivityRange": {
   "low": 0.07,
   "high": 0.13
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down capacity apportionment",
   "expression": "CH colo 274 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.079 → 0.08 (normalized)",
   "crossCheck": "Installed-base method (Mordor 850.6 MW incl. self-operated) → ~0.13 — Swiss market is self-operation-heavy"
  },
  "provenance": {
   "rationale": "Large self-operated share (CBRE Suisse: 340 MW commercial only) makes scope choice decisive → inferred, wide band."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
    "excerpt": "Switzerland 274 MW of colocation and scale-colocation IT power in 2025.",
    "attached": true
   },
   {
    "title": "CBRE Suisse — Swiss data-center market capacity",
    "sourceType": "analyst-estimate",
    "publisher": "CBRE Suisse",
    "date": "2026",
    "excerpt": "Commercial capacity (excluding self-operated infrastructure) is 340 MW across 121 sites; ~61% (209 MW) concentrated in the Zurich region.",
    "attached": true
   }
  ]
 },
 {
  "id": "serviceableFactor",
  "label": "Serviceable share of TAM",
  "kind": "assumption",
  "value": 0.55,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "needs-source",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.45,
   "high": 0.65
  },
  "funnelActive": true,
  "derivation": {
   "method": "Reachability assumption",
   "expression": "No public SAM/TAM benchmark for B2B hardware exists; EU cert stack (EN 50600, ecodesign 2019/424, CE/TÜV) justifies < 1.0 but doesn't quantify 0.55"
  },
  "provenance": {
   "rationale": "Assumption leaf — channel + regulatory reach; EU certification barriers documented qualitatively only.",
   "promotionPath": "Bottom-up channel-coverage model (named accounts × reachable share) → sourced serviceable %."
  },
  "evidence": [
   {
    "title": "EU ecodesign requirements for servers and data storage (2019/424)",
    "sourceType": "industry-report",
    "publisher": "EUR-Lex",
    "date": "2019",
    "excerpt": "EU ecodesign and certification requirements gate which demand is regulatory-clear for a new entrant — the qualitative basis of the serviceable haircut.",
    "attached": true
   }
  ]
 }
]

